import { describe, expect, it } from 'vitest';
import {
  createDaylightTopology,
  createSpacetimeSurface,
  createDaylightMesh,
  daylightGradientCSS,
  daylightGradientStopsForCanvas,
  isDaylight,
  daylightState,
  interpolateDaylightColor,
  DEFAULT_DAYLIGHT_PALETTE,
} from './daylight-topology';

describe('createDaylightTopology', () => {
  const observer = { latitudeDeg: 40, longitudeDeg: -74 }; // New York
  const packet = createDaylightTopology({ observer });

  it('produces a packet with source identifier', () => {
    expect(packet.source).toBe('GnosisDaylightTopology');
  });

  it('defaults to 55 resolution (Pleroma)', () => {
    expect(packet.resolution).toBe(55);
    expect(packet.gradientStops.length).toBe(55);
  });

  it('defaults to 1 pLo span', () => {
    expect(packet.spanPLo).toBe(1);
  });

  it('gradient stops cover [0, 1] range', () => {
    expect(packet.gradientStops[0].position).toBe(0);
    expect(packet.gradientStops[packet.gradientStops.length - 1].position).toBe(1);
  });

  it('gradient stops have monotonically increasing positions', () => {
    for (let i = 1; i < packet.gradientStops.length; i++) {
      expect(packet.gradientStops[i].position).toBeGreaterThan(
        packet.gradientStops[i - 1].position
      );
    }
  });

  it('gradient stops have valid twilight zones', () => {
    const validZones = ['day', 'civil', 'nautical', 'astronomical', 'night'];
    for (const stop of packet.gradientStops) {
      expect(validZones).toContain(stop.zone);
    }
  });

  it('summary fractions sum to approximately 1', () => {
    const total =
      packet.summary.daylightFraction +
      packet.summary.nightFraction +
      packet.summary.civilTwilightFraction +
      packet.summary.nauticalTwilightFraction +
      packet.summary.astronomicalTwilightFraction;
    expect(total).toBeCloseTo(1, 2);
  });

  it('has at least one band', () => {
    expect(packet.bands.length).toBeGreaterThan(0);
  });

  it('bands contain stops that match their zone', () => {
    for (const band of packet.bands) {
      for (const stop of band.gradientStops) {
        expect(stop.zone).toBe(band.zone);
      }
    }
  });

  it('includes gnostic time labels on each stop', () => {
    for (const stop of packet.gradientStops) {
      expect(typeof stop.gnosticTime).toBe('string');
      expect(stop.gnosticTime.length).toBeGreaterThan(0);
    }
  });
});

describe('daylightGradientCSS', () => {
  it('produces a valid CSS linear-gradient string', () => {
    const packet = createDaylightTopology({
      observer: { latitudeDeg: 0, longitudeDeg: 0 },
      resolution: 10,
    });
    const css = daylightGradientCSS(packet);
    expect(css).toMatch(/^linear-gradient\(to right,/);
    expect(css).toMatch(/rgba\(\d+,\d+,\d+,[\d.]+\)/);
    expect(css).toMatch(/%\)$/);
  });
});

describe('daylightGradientStopsForCanvas', () => {
  it('produces stops with offset and color', () => {
    const packet = createDaylightTopology({
      observer: { latitudeDeg: 0, longitudeDeg: 0 },
      resolution: 10,
    });
    const stops = daylightGradientStopsForCanvas(packet);
    expect(stops.length).toBe(10);
    for (const stop of stops) {
      expect(typeof stop.offset).toBe('number');
      expect(stop.offset).toBeGreaterThanOrEqual(0);
      expect(stop.offset).toBeLessThanOrEqual(1);
      expect(stop.color).toMatch(/^rgba\(/);
    }
  });
});

describe('isDaylight', () => {
  it('returns true at equator noon UTC', () => {
    expect(
      isDaylight({
        lat: 0,
        lon: 0,
        epochMs: Date.UTC(2026, 5, 21, 12, 0, 0),
      })
    ).toBe(true);
  });

  it('returns false at equator midnight UTC', () => {
    expect(
      isDaylight({
        lat: 0,
        lon: 0,
        epochMs: Date.UTC(2026, 5, 21, 0, 0, 0),
      })
    ).toBe(false);
  });

  it('respects longitude offset', () => {
    // Noon at lon=180 when UTC is midnight
    expect(
      isDaylight({
        lat: 0,
        lon: 180,
        epochMs: Date.UTC(2026, 5, 21, 0, 0, 0),
      })
    ).toBe(true);
  });
});

describe('daylightState', () => {
  it('returns a color and altitude for any coordinate', () => {
    const state = daylightState({
      lat: 51.5,
      lon: -0.1,
      epochMs: Date.UTC(2026, 5, 21, 12, 0, 0),
    });
    expect(typeof state.isDaylight).toBe('boolean');
    expect(typeof state.altitude.altitudeDeg).toBe('number');
    expect(typeof state.color.r).toBe('number');
    expect(state.color.r).toBeGreaterThanOrEqual(0);
    expect(state.color.r).toBeLessThanOrEqual(255);
  });
});

describe('interpolateDaylightColor', () => {
  it('returns day color at high altitude', () => {
    const color = interpolateDaylightColor(DEFAULT_DAYLIGHT_PALETTE, 45);
    // Should be close to sky blue
    expect(color.r).toBeGreaterThan(100);
    expect(color.b).toBeGreaterThan(200);
  });

  it('returns night color at very low altitude', () => {
    const color = interpolateDaylightColor(DEFAULT_DAYLIGHT_PALETTE, -45);
    // Should be close to void black
    expect(color.r).toBeLessThan(30);
    expect(color.g).toBeLessThan(30);
  });
});

describe('createSpacetimeSurface', () => {
  it('produces a grid with correct dimensions', () => {
    const surface = createSpacetimeSurface({
      latitudeDeg: 0,
      longitudeBins: 10,
      timeBins: 10,
    });
    expect(surface.source).toBe('GnosisDaylightSpacetime');
    expect(surface.cells.length).toBe(100); // 10 * 10
    expect(surface.longitudeBins).toBe(10);
    expect(surface.timeBins).toBe(10);
  });

  it('shows both day and night across full longitude', () => {
    const surface = createSpacetimeSurface({
      latitudeDeg: 0,
      longitudeBins: 36, // 10-degree bins
      timeBins: 1,       // single time slice
    });
    const zones = new Set(surface.cells.map((c) => c.zone));
    // At any given time, the equator should have both day and night zones
    expect(zones.size).toBeGreaterThan(1);
  });
});

describe('createDaylightMesh', () => {
  it('produces a mesh with correct resolution', () => {
    const mesh = createDaylightMesh({
      resolutionDeg: 10,
      minLat: -30,
      maxLat: 30,
      minLon: -30,
      maxLon: 30,
    });
    expect(mesh.source).toBe('GnosisDaylightMesh');
    expect(mesh.resolutionDeg).toBe(10);
    expect(mesh.latCount).toBe(7); // -30, -20, -10, 0, 10, 20, 30
    expect(mesh.lonCount).toBe(6); // -30, -20, -10, 0, 10, 20
    expect(mesh.cells.length).toBe(42);
  });

  it('has daylightFraction in [0, 1]', () => {
    const mesh = createDaylightMesh({
      resolutionDeg: 30,
    });
    expect(mesh.daylightFraction).toBeGreaterThanOrEqual(0);
    expect(mesh.daylightFraction).toBeLessThanOrEqual(1);
  });

  it('cells have isDaylight boolean', () => {
    const mesh = createDaylightMesh({
      resolutionDeg: 30,
      minLat: 0,
      maxLat: 0,
      minLon: -180,
      maxLon: 180,
    });
    for (const cell of mesh.cells) {
      expect(typeof cell.isDaylight).toBe('boolean');
    }
  });
});
